package com.weeklycommit.ai.rag;

import com.weeklycommit.domain.entity.CarryForwardLink;
import com.weeklycommit.domain.entity.ManagerComment;
import com.weeklycommit.domain.entity.ScopeChangeEvent;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.entity.WorkItem;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.springframework.stereotype.Component;

/**
 * Converts domain entities into {@link ChunkData} records suitable for
 * embedding and storage in Pinecone.
 *
 * <p>
 * Each chunk has a stable ID ({@code entityType:entityId}), a human-readable
 * text representation, and a flat {@code Map<String, String>} of metadata
 * stored alongside the vector for filtered retrieval.
 *
 * <p>
 * All fields are handled null-safely: optional values that are {@code null} are
 * replaced with an empty string in the text and omitted from metadata (or
 * stored as an empty string where the key is always expected).
 */
@Component
public class ChunkBuilder {

	// ── Inner record ─────────────────────────────────────────────────────

	/**
	 * A text chunk ready to be embedded and stored in Pinecone.
	 *
	 * @param id
	 *            stable Pinecone vector ID: {@code entityType:entityId}
	 * @param text
	 *            human-readable text that will be embedded
	 * @param metadata
	 *            flat string map stored alongside the vector
	 */
	public record ChunkData(String id, String text, Map<String, String> metadata) {
	}

	// ── Public build methods ─────────────────────────────────────────────

	/**
	 * Builds a chunk for a {@link WeeklyCommit}.
	 *
	 * <p>
	 * Text format: {@code "{title}" — {chessPiece}, {estimatePoints}pts.
	 * Description: {description}. Success criteria: {successCriteria}. Outcome:
	 * {outcome}. Notes: {outcomeNotes}}.
	 */
	public ChunkData buildCommitChunk(WeeklyCommit commit, WeeklyPlan plan) {
		String pts = commit.getEstimatePoints() != null ? commit.getEstimatePoints().toString() : "?";
		String chess = commit.getChessPiece() != null ? commit.getChessPiece().name() : "";
		String outcome = commit.getOutcome() != null ? commit.getOutcome().name() : "";

		String text = "\"" + commit.getTitle() + "\" — " + chess + ", " + pts + "pts. " + "Description: "
				+ orEmpty(commit.getDescription()) + ". " + "Success criteria: " + orEmpty(commit.getSuccessCriteria())
				+ ". " + "Outcome: " + outcome + ". " + "Notes: " + orEmpty(commit.getOutcomeNotes());

		Map<String, String> meta = new LinkedHashMap<>();
		meta.put("entityType", "commit");
		meta.put("entityId", str(commit.getId()));
		meta.put("userId", str(commit.getOwnerUserId()));
		meta.put("teamId", str(plan.getTeamId()));
		meta.put("planId", str(plan.getId()));
		meta.put("weekStartDate", plan.getWeekStartDate() != null ? plan.getWeekStartDate().toString() : "");

		return new ChunkData("commit:" + commit.getId(), text, meta);
	}

	/**
	 * Builds a chunk for a {@link ScopeChangeEvent}.
	 *
	 * <p>
	 * Text format: {@code Scope change ({category}): commit "{commitTitle}" —
	 * {reason}}.
	 */
	public ChunkData buildScopeChangeChunk(ScopeChangeEvent event, WeeklyCommit commit) {
		String category = event.getCategory() != null ? event.getCategory().name() : "";
		String commitTitle = commit != null ? commit.getTitle() : "";

		String text = "Scope change (" + category + "): commit \"" + commitTitle + "\" — " + orEmpty(event.getReason());

		Map<String, String> meta = new LinkedHashMap<>();
		meta.put("entityType", "scope_change");
		meta.put("entityId", str(event.getId()));
		meta.put("planId", str(event.getPlanId()));
		meta.put("commitId", str(event.getCommitId()));
		meta.put("userId", str(event.getChangedByUserId()));

		return new ChunkData("scope_change:" + event.getId(), text, meta);
	}

	/**
	 * Builds a chunk for a {@link CarryForwardLink}.
	 *
	 * <p>
	 * Text format: {@code Carry forward: "{commitTitle}" carried forward for
	 * {streak} week(s). Reason: {reason}. Notes: {reasonNotes}}.
	 */
	public ChunkData buildCarryForwardChunk(CarryForwardLink link, WeeklyCommit sourceCommit) {
		String commitTitle = sourceCommit != null ? sourceCommit.getTitle() : "";
		int streak = sourceCommit != null ? sourceCommit.getCarryForwardStreak() : 0;
		String reason = link.getReason() != null ? link.getReason().name() : "";

		String text = "Carry forward: \"" + commitTitle + "\" carried forward for " + streak + " week(s). " + "Reason: "
				+ reason + ". " + "Notes: " + orEmpty(link.getReasonNotes());

		Map<String, String> meta = new LinkedHashMap<>();
		meta.put("entityType", "carry_forward");
		meta.put("entityId", str(link.getId()));
		meta.put("sourceCommitId", str(link.getSourceCommitId()));
		meta.put("targetCommitId", str(link.getTargetCommitId()));

		return new ChunkData("carry_forward:" + link.getId(), text, meta);
	}

	/**
	 * Builds a chunk for a {@link ManagerComment}.
	 *
	 * <p>
	 * Text format: {@code Manager comment (week {weekStartDate}): {content}}.
	 */
	public ChunkData buildManagerCommentChunk(ManagerComment comment, WeeklyPlan plan) {
		String weekDate = plan.getWeekStartDate() != null ? plan.getWeekStartDate().toString() : "";

		String text = "Manager comment (week " + weekDate + "): " + orEmpty(comment.getContent());

		Map<String, String> meta = new LinkedHashMap<>();
		meta.put("entityType", "manager_comment");
		meta.put("entityId", str(comment.getId()));
		meta.put("planId", str(comment.getPlanId()));
		meta.put("userId", str(comment.getAuthorUserId()));
		meta.put("weekStartDate", weekDate);

		return new ChunkData("manager_comment:" + comment.getId(), text, meta);
	}

	/**
	 * Builds a chunk for a {@link WorkItem} (native ticket).
	 *
	 * <p>
	 * Text format: {@code {key}: {title}. Description: {description}. Status:
	 * {status}.}.
	 */
	public ChunkData buildWorkItemChunk(WorkItem item) {
		String status = item.getStatus() != null ? item.getStatus().name() : "";

		String text = item.getKey() + ": " + item.getTitle() + ". " + "Description: " + orEmpty(item.getDescription())
				+ ". " + "Status: " + status + ".";

		Map<String, String> meta = new LinkedHashMap<>();
		meta.put("entityType", "ticket");
		meta.put("entityId", str(item.getId()));
		meta.put("teamId", str(item.getTeamId()));

		return new ChunkData("ticket:" + item.getId(), text, meta);
	}

	/**
	 * Builds a plan-level summary chunk from a {@link WeeklyPlan} and its commits.
	 *
	 * <p>
	 * Text format: {@code Week of {weekStartDate}: {count} commits,
	 * {totalPoints}pts, {state}}.
	 */
	public ChunkData buildPlanSummaryChunk(WeeklyPlan plan, List<WeeklyCommit> commits) {
		int count = commits != null ? commits.size() : 0;
		int totalPoints = commits != null
				? commits.stream().mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0).sum()
				: 0;
		String weekDate = plan.getWeekStartDate() != null ? plan.getWeekStartDate().toString() : "";
		String state = plan.getState() != null ? plan.getState().name() : "";

		String text = "Week of " + weekDate + ": " + count + " commits, " + totalPoints + "pts, " + state;

		Map<String, String> meta = new LinkedHashMap<>();
		meta.put("entityType", "plan_summary");
		meta.put("entityId", str(plan.getId()));
		meta.put("teamId", str(plan.getTeamId()));
		meta.put("userId", str(plan.getOwnerUserId()));
		meta.put("weekStartDate", weekDate);

		return new ChunkData("plan_summary:" + plan.getId(), text, meta);
	}

	// ── Private helpers ──────────────────────────────────────────────────

	private static String orEmpty(String value) {
		return value != null ? value : "";
	}

	private static String str(UUID uuid) {
		return uuid != null ? uuid.toString() : "";
	}
}

package com.weeklycommit.plan.service;

import com.weeklycommit.audit.service.AuditLogService;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.plan.dto.CreateCommitRequest;
import com.weeklycommit.plan.dto.UpdateCommitRequest;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.rcdo.service.RcdoLinkageValidator;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class CommitService {

	/** Valid Fibonacci-scale estimate values. */
	private static final Set<Integer> VALID_ESTIMATE_POINTS = Set.of(1, 2, 3, 5, 8);

	private static final int MAX_KING_PER_WEEK = 1;
	private static final int MAX_QUEEN_PER_WEEK = 2;

	private final WeeklyCommitRepository commitRepo;
	private final WeeklyPlanRepository planRepo;
	private final WorkItemRepository workItemRepo;
	private final RcdoLinkageValidator rcdoLinkageValidator;
	private final AuditLogService auditLogService;

	public CommitService(WeeklyCommitRepository commitRepo, WeeklyPlanRepository planRepo,
			WorkItemRepository workItemRepo, RcdoLinkageValidator rcdoLinkageValidator,
			AuditLogService auditLogService) {
		this.commitRepo = commitRepo;
		this.planRepo = planRepo;
		this.workItemRepo = workItemRepo;
		this.rcdoLinkageValidator = rcdoLinkageValidator;
		this.auditLogService = auditLogService;
	}

	// -------------------------------------------------------------------------
	// Create
	// -------------------------------------------------------------------------

	public WeeklyCommit createCommit(UUID planId, CreateCommitRequest req, UUID actorUserId) {
		WeeklyPlan plan = findPlan(planId);
		validateDraftState(plan);

		// Validate chess piece limits
		validateChessPieceLimits(planId, req.chessPiece(), null);

		// Validate estimate points if provided
		validateEstimatePoints(req.estimatePoints());

		// Success criteria required for King / Queen
		validateSuccessCriteria(req.chessPiece(), req.successCriteria());

		// Resolve RCDO: use explicit value, else default from ticket
		UUID rcdoNodeId = resolveRcdoNodeId(req.rcdoNodeId(), req.workItemId());

		// Validate RCDO linkage if provided
		if (rcdoNodeId != null) {
			rcdoLinkageValidator.validateCommitLinkage(rcdoNodeId);
		}

		WeeklyCommit commit = new WeeklyCommit();
		commit.setPlanId(planId);
		commit.setOwnerUserId(plan.getOwnerUserId());
		commit.setTitle(req.title());
		commit.setChessPiece(req.chessPiece());
		commit.setDescription(req.description());
		commit.setRcdoNodeId(rcdoNodeId);
		commit.setWorkItemId(req.workItemId());
		commit.setEstimatePoints(req.estimatePoints());
		commit.setSuccessCriteria(req.successCriteria());
		commit.setPriorityOrder(nextPriorityOrder(planId));

		WeeklyCommit saved = commitRepo.save(commit);
		auditLogService.record(AuditLogService.COMMIT_CREATED, actorUserId, "IC", AuditLogService.TARGET_COMMIT,
				saved.getId(), null, Map.of("planId", planId.toString(), "title", req.title()));
		return saved;
	}

	// -------------------------------------------------------------------------
	// Update
	// -------------------------------------------------------------------------

	public WeeklyCommit updateCommit(UUID planId, UUID commitId, UpdateCommitRequest req, UUID actorUserId) {
		WeeklyCommit commit = findCommit(commitId);
		validateCommitBelongsToPlan(planId, commit);
		WeeklyPlan plan = findPlan(commit.getPlanId());
		validateDraftState(plan);
		Map<String, Object> beforePayload = auditPayload(commit);

		// Effective values after applying patch
		ChessPiece effectivePiece = req.chessPiece() != null ? req.chessPiece() : commit.getChessPiece();
		String effectiveCriteria = req.successCriteria() != null ? req.successCriteria() : commit.getSuccessCriteria();
		Integer effectivePoints = req.estimatePoints() != null ? req.estimatePoints() : commit.getEstimatePoints();
		UUID effectiveRcdo = req.rcdoNodeId() != null ? req.rcdoNodeId() : commit.getRcdoNodeId();

		// If chess piece is changing, re-validate limits excluding this commit
		if (req.chessPiece() != null && req.chessPiece() != commit.getChessPiece()) {
			validateChessPieceLimits(commit.getPlanId(), req.chessPiece(), commitId);
		}

		validateEstimatePoints(effectivePoints);
		validateSuccessCriteria(effectivePiece, effectiveCriteria);

		if (effectiveRcdo != null && !effectiveRcdo.equals(commit.getRcdoNodeId())) {
			rcdoLinkageValidator.validateCommitLinkage(effectiveRcdo);
		}

		// Apply non-null fields
		if (req.title() != null && !req.title().isBlank()) {
			commit.setTitle(req.title());
		}
		if (req.chessPiece() != null) {
			commit.setChessPiece(req.chessPiece());
		}
		if (req.description() != null) {
			commit.setDescription(req.description());
		}
		if (req.rcdoNodeId() != null) {
			commit.setRcdoNodeId(req.rcdoNodeId());
		}
		if (req.workItemId() != null) {
			commit.setWorkItemId(req.workItemId());
		}
		if (req.estimatePoints() != null) {
			commit.setEstimatePoints(req.estimatePoints());
		}
		if (req.successCriteria() != null) {
			commit.setSuccessCriteria(req.successCriteria());
		}

		WeeklyCommit saved = commitRepo.save(commit);
		auditLogService.record(AuditLogService.COMMIT_UPDATED, actorUserId, "IC", AuditLogService.TARGET_COMMIT,
				saved.getId(), beforePayload, auditPayload(saved));
		return saved;
	}

	// -------------------------------------------------------------------------
	// Delete
	// -------------------------------------------------------------------------

	public void deleteCommit(UUID planId, UUID commitId, UUID actorUserId) {
		WeeklyCommit commit = findCommit(commitId);
		validateCommitBelongsToPlan(planId, commit);
		WeeklyPlan plan = findPlan(commit.getPlanId());
		validateDraftState(plan);

		auditLogService.record(AuditLogService.COMMIT_DELETED, actorUserId, "IC", AuditLogService.TARGET_COMMIT,
				commitId, Map.of("planId", planId.toString(), "title", commit.getTitle()), null);
		commitRepo.delete(commit);

		// Re-number remaining commits sequentially
		List<WeeklyCommit> remaining = commitRepo.findByPlanIdOrderByPriorityOrder(planId);
		for (int i = 0; i < remaining.size(); i++) {
			remaining.get(i).setPriorityOrder(i + 1);
			commitRepo.save(remaining.get(i));
		}
	}

	// -------------------------------------------------------------------------
	// Reorder
	// -------------------------------------------------------------------------

	public List<WeeklyCommit> reorderCommits(UUID planId, List<UUID> orderedCommitIds, UUID actorUserId) {
		WeeklyPlan plan = findPlan(planId);
		validateDraftState(plan);

		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);
		Set<UUID> planIds = new HashSet<>();
		for (WeeklyCommit c : commits) {
			planIds.add(c.getId());
		}

		if (!planIds.equals(new HashSet<>(orderedCommitIds))) {
			throw new PlanValidationException("Reorder list must contain exactly all commit IDs for this plan");
		}

		for (int i = 0; i < orderedCommitIds.size(); i++) {
			final int newOrder = i + 1;
			UUID cId = orderedCommitIds.get(i);
			commits.stream().filter(c -> c.getId().equals(cId)).findFirst().ifPresent(c -> {
				c.setPriorityOrder(newOrder);
				commitRepo.save(c);
			});
		}

		return commitRepo.findByPlanIdOrderByPriorityOrder(planId);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	WeeklyCommit findCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private WeeklyPlan findPlan(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	private void validateDraftState(WeeklyPlan plan) {
		if (plan.getState() != PlanState.DRAFT) {
			throw new PlanValidationException(
					"Plan " + plan.getId() + " is not in DRAFT state (current: " + plan.getState() + ")");
		}
	}

	private void validateCommitBelongsToPlan(UUID planId, WeeklyCommit commit) {
		if (!commit.getPlanId().equals(planId)) {
			throw new PlanValidationException("Commit " + commit.getId() + " does not belong to plan " + planId);
		}
	}

	void validateChessPieceLimits(UUID planId, ChessPiece piece, UUID excludeCommitId) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);
		long count = commits.stream().filter(c -> excludeCommitId == null || !c.getId().equals(excludeCommitId))
				.filter(c -> c.getChessPiece() == piece).count();

		if (piece == ChessPiece.KING && count >= MAX_KING_PER_WEEK) {
			throw new PlanValidationException("Maximum " + MAX_KING_PER_WEEK + " King commit(s) per week exceeded");
		}
		if (piece == ChessPiece.QUEEN && count >= MAX_QUEEN_PER_WEEK) {
			throw new PlanValidationException("Maximum " + MAX_QUEEN_PER_WEEK + " Queen commit(s) per week exceeded");
		}
	}

	void validateEstimatePoints(Integer points) {
		if (points != null && !VALID_ESTIMATE_POINTS.contains(points)) {
			throw new PlanValidationException("Estimate points must be one of {1, 2, 3, 5, 8}, got: " + points);
		}
	}

	void validateSuccessCriteria(ChessPiece piece, String successCriteria) {
		if ((piece == ChessPiece.KING || piece == ChessPiece.QUEEN)
				&& (successCriteria == null || successCriteria.isBlank())) {
			throw new PlanValidationException("Success criteria is required for " + piece + " commits");
		}
	}

	private int nextPriorityOrder(UUID planId) {
		return (int) (commitRepo.countByPlanId(planId) + 1);
	}

	private UUID resolveRcdoNodeId(UUID requestedRcdo, UUID workItemId) {
		if (requestedRcdo != null) {
			return requestedRcdo;
		}
		if (workItemId != null) {
			return workItemRepo.findById(workItemId).map(WorkItem::getRcdoNodeId).orElse(null);
		}
		return null;
	}

	private Map<String, Object> auditPayload(WeeklyCommit commit) {
		Map<String, Object> payload = new java.util.LinkedHashMap<>();
		payload.put("planId", commit.getPlanId().toString());
		payload.put("title", commit.getTitle());
		payload.put("chessPiece", commit.getChessPiece() != null ? commit.getChessPiece().name() : null);
		payload.put("priorityOrder", commit.getPriorityOrder());
		payload.put("description", commit.getDescription());
		payload.put("estimatePoints", commit.getEstimatePoints());
		payload.put("successCriteria", commit.getSuccessCriteria());
		payload.put("rcdoNodeId", commit.getRcdoNodeId() != null ? commit.getRcdoNodeId().toString() : null);
		payload.put("workItemId", commit.getWorkItemId() != null ? commit.getWorkItemId().toString() : null);
		return payload;
	}
}

package com.weeklycommit.reconcile.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.domain.entity.LockSnapshotHeader;
import com.weeklycommit.domain.entity.ScopeChangeEvent;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.CommitOutcome;
import com.weeklycommit.domain.enums.NotificationEvent;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.enums.ScopeChangeCategory;
import com.weeklycommit.domain.repository.LockSnapshotHeaderRepository;
import com.weeklycommit.domain.repository.ScopeChangeEventRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.notification.service.NotificationService;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.reconcile.dto.AddCommitData;
import com.weeklycommit.reconcile.dto.EditCommitChanges;
import com.weeklycommit.reconcile.dto.ManagerException;
import com.weeklycommit.reconcile.dto.ScopeChangeEventResponse;
import com.weeklycommit.reconcile.dto.ScopeChangeTimelineResponse;
import com.weeklycommit.report.service.ReadModelRefreshService;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Handles post-lock scope changes on a LOCKED plan. All commit mutations after
 * lock are routed through this service so every change is recorded as an
 * immutable {@link ScopeChangeEvent} with before/after values.
 */
@Service
@Transactional
public class ScopeChangeService {

	private static final Logger log = LoggerFactory.getLogger(ScopeChangeService.class);

	/** King-related change threshold that triggers a manager exception. */
	private static final ChessPiece KING = ChessPiece.KING;

	/**
	 * Percent increase in total estimate points that triggers a manager exception.
	 */
	private static final double POINTS_INCREASE_THRESHOLD_PCT = 0.20;

	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ScopeChangeEventRepository eventRepo;
	private final LockSnapshotHeaderRepository lockSnapshotRepo;
	private final ObjectMapper objectMapper;
	private final NotificationService notificationService;

	private final ReadModelRefreshService readModelRefreshService;

	public ScopeChangeService(WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			ScopeChangeEventRepository eventRepo, LockSnapshotHeaderRepository lockSnapshotRepo,
			ObjectMapper objectMapper, NotificationService notificationService,
			ReadModelRefreshService readModelRefreshService) {
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.eventRepo = eventRepo;
		this.lockSnapshotRepo = lockSnapshotRepo;
		this.objectMapper = objectMapper;
		this.notificationService = notificationService;
		this.readModelRefreshService = readModelRefreshService;
	}

	// -------------------------------------------------------------------------
	// Add post-lock commit
	// -------------------------------------------------------------------------

	/**
	 * Adds a new commit to a LOCKED plan and records a COMMIT_ADDED scope-change
	 * event.
	 *
	 * @return updated change timeline including the new event
	 */
	public ScopeChangeTimelineResponse addPostLockCommit(UUID planId, AddCommitData data, String reason,
			UUID actorUserId) {
		validateReason(reason);
		if (data == null) {
			throw new PlanValidationException("Commit data is required for ADD scope changes");
		}
		WeeklyPlan plan = requireLockedPlan(planId);

		WeeklyCommit commit = new WeeklyCommit();
		commit.setPlanId(planId);
		commit.setOwnerUserId(plan.getOwnerUserId());
		commit.setTitle(data.title());
		commit.setChessPiece(data.chessPiece());
		commit.setDescription(data.description());
		commit.setRcdoNodeId(data.rcdoNodeId());
		commit.setWorkItemId(data.workItemId());
		commit.setEstimatePoints(data.estimatePoints());
		commit.setSuccessCriteria(data.successCriteria());
		commit.setPriorityOrder(nextPriorityOrder(planId));
		WeeklyCommit saved = commitRepo.save(commit);

		ScopeChangeEvent event = newEvent(planId, saved.getId(), ScopeChangeCategory.COMMIT_ADDED, actorUserId, reason);
		event.setPreviousValue(null);
		event.setNewValue(toJson(commitToMap(saved)));
		eventRepo.save(event);

		if (saved.getChessPiece() == KING) {
			notifyManagerOfKingScopeChange(plan,
					"A King-level commit was added post-lock on plan for week " + plan.getWeekStartDate() + ".");
		}

		triggerReadModelRefresh(planId);
		return getChangeTimeline(planId);
	}

	// -------------------------------------------------------------------------
	// Remove post-lock commit
	// -------------------------------------------------------------------------

	/**
	 * Marks an existing commit on a LOCKED plan as canceled and records a
	 * COMMIT_REMOVED scope-change event.
	 *
	 * @return updated change timeline
	 */
	public ScopeChangeTimelineResponse removePostLockCommit(UUID planId, UUID commitId, String reason,
			UUID actorUserId) {
		validateReason(reason);
		WeeklyCommit commit = requireCommit(commitId);
		validateCommitBelongsToPlan(planId, commit);
		requireLockedPlan(commit.getPlanId());

		commit.setOutcome(CommitOutcome.CANCELED);
		commit.setOutcomeNotes(reason);
		commitRepo.save(commit);

		ScopeChangeEvent event = newEvent(commit.getPlanId(), commitId, ScopeChangeCategory.COMMIT_REMOVED, actorUserId,
				reason);
		event.setPreviousValue(toJson(java.util.Map.of("outcome", "null")));
		event.setNewValue(toJson(java.util.Map.of("outcome", CommitOutcome.CANCELED.name())));
		eventRepo.save(event);

		triggerReadModelRefresh(commit.getPlanId());
		return getChangeTimeline(commit.getPlanId());
	}

	// -------------------------------------------------------------------------
	// Edit post-lock commit
	// -------------------------------------------------------------------------

	/**
	 * Applies mutable-field changes to a commit on a LOCKED plan. A separate
	 * SCOPE_CHANGE event is created for each changed field.
	 *
	 * @return updated change timeline
	 */
	public ScopeChangeTimelineResponse editPostLockCommit(UUID planId, UUID commitId, EditCommitChanges changes,
			String reason, UUID actorUserId) {
		validateReason(reason);
		if (changes == null) {
			throw new PlanValidationException("Changes payload is required for EDIT scope changes");
		}
		WeeklyCommit commit = requireCommit(commitId);
		validateCommitBelongsToPlan(planId, commit);
		requireLockedPlan(commit.getPlanId());

		if (changes.estimatePoints() != null && !changes.estimatePoints().equals(commit.getEstimatePoints())) {
			recordFieldChange(commit, ScopeChangeCategory.ESTIMATE_CHANGED, actorUserId, reason,
					str(commit.getEstimatePoints()), str(changes.estimatePoints()));
			commit.setEstimatePoints(changes.estimatePoints());
		}

		boolean kingChangeDetected = false;
		if (changes.chessPiece() != null && changes.chessPiece() != commit.getChessPiece()) {
			ChessPiece previousPiece = commit.getChessPiece();
			recordFieldChange(commit, ScopeChangeCategory.CHESS_PIECE_CHANGED, actorUserId, reason, str(previousPiece),
					str(changes.chessPiece()));
			commit.setChessPiece(changes.chessPiece());
			// King involved in the change?
			if (KING == previousPiece || KING == changes.chessPiece()) {
				kingChangeDetected = true;
			}
		}

		if (changes.rcdoNodeId() != null && !changes.rcdoNodeId().equals(commit.getRcdoNodeId())) {
			recordFieldChange(commit, ScopeChangeCategory.RCDO_CHANGED, actorUserId, reason,
					str(commit.getRcdoNodeId()), str(changes.rcdoNodeId()));
			commit.setRcdoNodeId(changes.rcdoNodeId());
		}

		if (changes.priorityOrder() != null && changes.priorityOrder() != commit.getPriorityOrder()) {
			recordFieldChange(commit, ScopeChangeCategory.PRIORITY_CHANGED, actorUserId, reason,
					str(commit.getPriorityOrder()), str(changes.priorityOrder()));
			commit.setPriorityOrder(changes.priorityOrder());
		}

		commitRepo.save(commit);

		// Notify team manager when King is involved in a post-lock scope change
		if (kingChangeDetected) {
			WeeklyPlan plan = planRepo.findById(planId).orElse(null);
			if (plan != null) {
				notifyManagerOfKingScopeChange(plan,
						"A King-level commit was modified post-lock on plan for week " + plan.getWeekStartDate() + ".");
			}
		}

		triggerReadModelRefresh(commit.getPlanId());
		return getChangeTimeline(commit.getPlanId());
	}

	// -------------------------------------------------------------------------
	// Change timeline
	// -------------------------------------------------------------------------

	/**
	 * Returns the full chronological scope-change timeline for a plan, together
	 * with any manager-exception flags.
	 */
	@Transactional(readOnly = true)
	public ScopeChangeTimelineResponse getChangeTimeline(UUID planId) {
		List<ScopeChangeEvent> events = eventRepo.findByPlanIdOrderByCreatedAtAsc(planId);
		List<ScopeChangeEventResponse> responses = events.stream().map(ScopeChangeEventResponse::from).toList();
		List<ManagerException> exceptions = detectManagerExceptions(planId, events);
		return new ScopeChangeTimelineResponse(responses, exceptions);
	}

	// -------------------------------------------------------------------------
	// Manager exception detection
	// -------------------------------------------------------------------------

	/**
	 * Evaluates the current scope-change events against manager-exception
	 * thresholds. Flags are re-derived from events each call (no persistent state).
	 */
	List<ManagerException> detectManagerExceptions(UUID planId, List<ScopeChangeEvent> events) {
		List<ManagerException> exceptions = new ArrayList<>();

		// Rule 1: King added or changed to/from KING
		boolean kingException = false;
		for (ScopeChangeEvent e : events) {
			if (e.getCategory() == ScopeChangeCategory.COMMIT_ADDED) {
				try {
					JsonNode node = objectMapper.readTree(e.getNewValue());
					if (KING.name().equals(node.path("chessPiece").asText(null))) {
						kingException = true;
					}
				} catch (Exception ignored) {
					// malformed JSON — skip
				}
			} else if (e.getCategory() == ScopeChangeCategory.CHESS_PIECE_CHANGED) {
				String prev = e.getPreviousValue();
				String next = e.getNewValue();
				if (KING.name().equals(prev) || KING.name().equals(next)) {
					kingException = true;
				}
			}
		}
		if (kingException) {
			exceptions.add(new ManagerException(ManagerException.TYPE_KING_CHANGE,
					"A King-level commit was added or changed post-lock"));
		}

		// Rule 2: Total estimate points increased >20% from baseline
		lockSnapshotRepo.findByPlanId(planId).ifPresent(header -> {
			int baselinePoints = parseBaselinePoints(header);
			if (baselinePoints > 0) {
				int currentPoints = commitRepo.findByPlanIdOrderByPriorityOrder(planId).stream()
						.filter(c -> c.getOutcome() != CommitOutcome.CANCELED)
						.mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0).sum();
				double increase = (double) (currentPoints - baselinePoints) / baselinePoints;
				if (increase > POINTS_INCREASE_THRESHOLD_PCT) {
					exceptions.add(new ManagerException(ManagerException.TYPE_POINTS_INCREASE_20PCT,
							String.format("Total estimate points increased %.0f%% from baseline (%d → %d points)",
									increase * 100, baselinePoints, currentPoints)));
				}
			}
		});

		return exceptions;
	}

	// -------------------------------------------------------------------------
	// Helpers
	// -------------------------------------------------------------------------

	private void notifyManagerOfKingScopeChange(WeeklyPlan plan, String body) {
		try {
			notificationService.findManagerForTeam(plan.getTeamId())
					.ifPresent(managerId -> notificationService.createNotification(managerId,
							NotificationEvent.MANAGER_EXCEPTION_DIGEST, "King-level commit changed post-lock", body,
							plan.getId(), "PLAN"));
		} catch (Exception ex) {
			log.warn("Failed to send King-change manager notification for plan {}: {}", plan.getId(), ex.getMessage());
		}
	}

	private WeeklyPlan requireLockedPlan(UUID planId) {
		WeeklyPlan plan = planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
		if (plan.getState() != PlanState.LOCKED) {
			throw new PlanValidationException(
					"Scope changes are only allowed on LOCKED plans; current state: " + plan.getState());
		}
		return plan;
	}

	private WeeklyCommit requireCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private void validateCommitBelongsToPlan(UUID planId, WeeklyCommit commit) {
		if (!commit.getPlanId().equals(planId)) {
			throw new PlanValidationException("Commit " + commit.getId() + " does not belong to plan " + planId);
		}
	}

	private static void validateReason(String reason) {
		if (reason == null || reason.isBlank()) {
			throw new PlanValidationException("A non-empty reason is required for all post-lock scope changes");
		}
	}

	private ScopeChangeEvent newEvent(UUID planId, UUID commitId, ScopeChangeCategory category, UUID actorUserId,
			String reason) {
		ScopeChangeEvent e = new ScopeChangeEvent();
		e.setPlanId(planId);
		e.setCommitId(commitId);
		e.setCategory(category);
		e.setChangedByUserId(
				actorUserId != null ? actorUserId : UUID.fromString("00000000-0000-0000-0000-000000000000"));
		e.setReason(reason);
		return e;
	}

	private void recordFieldChange(WeeklyCommit commit, ScopeChangeCategory category, UUID actorUserId, String reason,
			String previousValue, String newValue) {
		ScopeChangeEvent e = newEvent(commit.getPlanId(), commit.getId(), category, actorUserId, reason);
		e.setPreviousValue(previousValue);
		e.setNewValue(newValue);
		eventRepo.save(e);
	}

	private int parseBaselinePoints(LockSnapshotHeader header) {
		try {
			JsonNode root = objectMapper.readTree(header.getSnapshotPayload());
			JsonNode commits = root.path("commits");
			if (!commits.isArray())
				return 0;
			int total = 0;
			for (JsonNode c : commits) {
				JsonNode ep = c.path("estimatePoints");
				if (!ep.isMissingNode() && !ep.isNull()) {
					total += ep.asInt(0);
				}
			}
			return total;
		} catch (JsonProcessingException e) {
			return 0;
		}
	}

	private int nextPriorityOrder(UUID planId) {
		return (int) (commitRepo.countByPlanId(planId) + 1);
	}

	private java.util.Map<String, Object> commitToMap(WeeklyCommit c) {
		java.util.Map<String, Object> m = new java.util.LinkedHashMap<>();
		m.put("id", str(c.getId()));
		m.put("title", c.getTitle());
		m.put("chessPiece", c.getChessPiece() != null ? c.getChessPiece().name() : null);
		m.put("estimatePoints", c.getEstimatePoints());
		m.put("rcdoNodeId", str(c.getRcdoNodeId()));
		m.put("priorityOrder", c.getPriorityOrder());
		return m;
	}

	private String toJson(Object o) {
		try {
			return objectMapper.writeValueAsString(o);
		} catch (JsonProcessingException e) {
			throw new IllegalStateException("JSON serialisation failed", e);
		}
	}

	private static String str(Object o) {
		return o != null ? o.toString() : null;
	}

	private void triggerReadModelRefresh(UUID planId) {
		try {
			readModelRefreshService.refreshForPlan(planId);
		} catch (Exception ex) {
			log.warn("Failed to refresh read models for plan {}: {}", planId, ex.getMessage());
		}
	}
}

package com.weeklycommit.carryforward.service;

import com.weeklycommit.carryforward.dto.CarryForwardLineageDetailResponse;
